async def upload_document(
		session: aiohttp.ClientSession,
		base_url: str,
		doc: dict,
		retries: int = 3
		) -> Optional[dict]:

	url = f"{base_url}/api/v1/document/"

	for attempt in range(1, retries + 1):
		try:
			async with session.post(url, json = doc, timeout = 60) as response:
				if response.status == 200:
					data = await response.json()
					print(f"[{response.status}] {doc['title']}")
					return data
				else:
					text = await response.text()
					print(f"[{response.status}] {doc['title']}: {text[:200]}")

					if attempt < retries:
						await asyncio.sleep(2 ** attempt)
					else:
						return None

		except asyncio.TimeoutError:
			print(f"Timeout: {doc['title']} (try {attempt})")
			if attempt < retries:
				await asyncio.sleep(2 ** attempt)

		except Exception as e:
			print(f" Error: {doc['title']} - {e}")
			if attempt < retries:
				await asyncio.sleep(2 ** attempt)

	return None


async def main():
	base_url = "http://localhost:8000"

	print(f"Загрузка {len(DOCUMENTS)} документов в OnboardAI...")
	print("-" * 60)

	connector = aiohttp.TCPConnector(limit = 5)

	async with aiohttp.ClientSession(connector = connector) as session:
		tasks = [
			upload_document(session, base_url, doc)
			for doc in DOCUMENTS
			]

		semaphore = asyncio.Semaphore(3)  # Не более 3 одновременных запросов

		async def bounded_upload(doc):
			async with semaphore:
				return await upload_document(session, base_url, doc)

		results = await asyncio.gather(*[bounded_upload(doc) for doc in DOCUMENTS])

	print("Finish")


if __name__ == "__main__":
	asyncio.run(main())